#!/bin/bash

random() {
    LC_ALL=C tr -dc A-Za-z0-9 &lt;/dev/urandom | head -c &quot;$1&quot;
}

query() {
    q=$(curl -s -u natas28:skrwxciAe6Dnb0VfFDzDEHcCzQmv3Gd4 -I -w &#039;%{url}\n&#039; &quot;natas28.natas.labs.overthewire.org/$1&quot; | grep search.php | cut -d &#039; &#039; -f 2- | cut -d &#039;=&#039; -f 2)
    q=$(php -r &quot;echo urldecode(trim(&#039;$q&#039;));&quot;)
    echo &quot;$q&quot; | base64 -d | xxd -p | tr -d &quot; \n&quot; | fold -w 32
}

for i in {1..15}; do
    for _ in {1..3}; do
        p=$(random &quot;$i&quot;)
        echo &quot;$p: ($i)&quot;
        query &quot;$p&quot;
        printf &quot;\n\n&quot;
    done
done
